import{_ as a,o as l,c as i,a0 as o}from"./chunks/framework.BFy5Ffxw.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function c(d,e,n,r,s,h){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to cymbal are documented here.</p><h2 id="_0-2-0-2026-03-23" tabindex="-1">[0.2.0] - 2026-03-23 <a class="header-anchor" href="#_0-2-0-2026-03-23" aria-label="Permalink to &quot;[0.2.0] - 2026-03-23&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>All commands now output agent-native frontmatter+content format by default (YAML metadata + content body, optimized for LLM token efficiency)</li><li><code>refs</code> and <code>impact</code> deduplicate identical call sites — grouped by file with site count</li><li><code>context</code> callers section uses the same dedup</li><li><code>search</code> results ranked by relevance: exact name match first, then prefix, then contains</li><li>Default limits lowered: refs 50→20, impact 100→50, search 50→20</li><li><code>refs</code>, <code>impact</code>, and <code>context</code> now show actual source lines at call sites, not just line numbers</li></ul><h2 id="_0-1-0-2026-03-23" tabindex="-1">[0.1.0] - 2026-03-23 <a class="header-anchor" href="#_0-1-0-2026-03-23" aria-label="Permalink to &quot;[0.1.0] - 2026-03-23&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Core indexing engine with tree-sitter parsing, SQLite FTS5 storage, and AI summaries via oneagent</li><li>Batched summarization with diff tracking and model selection</li><li><code>cymbal index</code> — index a codebase</li><li><code>cymbal ls</code> — list files and repo stats</li><li><code>cymbal outline</code> — show file structure</li><li><code>cymbal search</code> — symbol and text search</li><li><code>cymbal show</code> — display symbol source</li><li><code>cymbal refs</code> — find references to a symbol</li><li><code>cymbal importers</code> — reverse import lookup</li><li><code>cymbal impact</code> — transitive caller analysis</li><li><code>cymbal diff</code> — git diff scoped to a symbol</li><li><code>cymbal context</code> — bundled source, callers, and imports in one call</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Overlapping sub-repo detection prevents duplicate symbol indexing</li></ul>',10)])])}const f=a(t,[["render",c]]);export{u as __pageData,f as default};
